		assert.deepEqual(reloaded.list().map((s) => s.displayName), ["mcp.example.com/mcp (2)", "mcp.example.com/mcp (3)"]);
		const onDisk = yaml.parse(fs.readFileSync(path.join(tmpDir, "marketplace-sources.yaml"), "utf-8")) as any;
		assert.equal(onDisk.sources[0].displayName, "mcp.example.com/mcp (2)");
